+    fn test_abs_basic() {
+        assert_eq!(abs(42), 42);
+        assert_eq!(abs(-42), 42);
+        assert_eq!(abs(0), 0);
+    }
+
+    #[test]
+    fn test_abs_min() {
+        // wrapping_abs of i32::MIN wraps to i32::MIN (undefined in C, defined in Rust)
+        assert_eq!(abs(i32::MIN), i32::MIN);
+    }
+
+    #[test]
+    fn test_labs_basic() {
+        assert_eq!(labs(42), 42);
+        assert_eq!(labs(-42), 42);
+    }
+
+    #[test]
+    fn test_div_basic() {
+        let r = div(7, 3);
+        assert_eq!(r.quot, 2);
+        assert_eq!(r.rem, 1);
+    }
+
+    #[test]
+    fn test_div_negative() {
+        let r = div(-7, 3);
+        assert_eq!(r.quot, -2);
+        assert_eq!(r.rem, -1);
+    }
+
+    #[test]
+    fn test_div_zero_denom() {
+        let r = div(7, 0);
+        assert_eq!(r.quot, 0);
+        assert_eq!(r.rem, 0);
+    }
+
+    #[test]
+    fn test_ldiv_basic() {
+        let r = ldiv(100, 7);
+        assert_eq!(r.quot, 14);
+        assert_eq!(r.rem, 2);
+    }
+
+    #[test]
+    fn test_ffs_basic() {
+        assert_eq!(ffs(0), 0);
+        assert_eq!(ffs(1), 1);
+        assert_eq!(ffs(2), 2);
+        assert_eq!(ffs(0b1000), 4);
+        assert_eq!(ffs(0b1010), 2);
+    }
+
+    #[test]
+    fn test_ffsl_basic() {
+        assert_eq!(ffsl(0), 0);
+        assert_eq!(ffsl(1i64 << 32), 33);
+    }
+
+    #[test]
+    fn test_ffsll_basic() {
+        assert_eq!(ffsll(0), 0);
+        assert_eq!(ffsll(1i64 << 63), 64);
+    }
+}

